class Solution {
    public int racecar(int target) {
        int[] dp = new int[target + 1];
        java.util.Arrays.fill(dp, Integer.MAX_VALUE);
        dp[0] = 0;
        for (int t = 1; t <= target; t++) {
            int m = 32 - Integer.numberOfLeadingZeros(t);
            if (t == (1 << m) - 1) {
                dp[t] = m;
                continue;
            }
            for (int i = 0; i < m - 1; i++) {
                dp[t] = Math.min(dp[t], m + 1 + i + dp[t - (1 << (m - 1)) + (1 << i)]);
            }
            if ((1 << m) - 1 - t < t) {
                dp[t] = Math.min(dp[t], m + 1 + dp[(1 << m) - 1 - t]);
            }
        }
        return dp[target];
    }
}
```
